python_code:
class TodoItem:
    def __init__(self, title, done=False):
        self.title = title
        self.done = done

    def mark_done(self):
        self.done = True

    def label(self):
        if self.done:
            return "[x] " + self.title
        return "[ ] " + self.title

task = TodoItem("write report")
print(task.label())
task.mark_done()
print(task.label())

